def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            print(".", end="")
    if wlan.isconnected():
        print("\nConnected! IP:", wlan.ifconfig()[0])
        return wlan.ifconfig()[0]
    else:
        print("\nFailed to connect to WiFi")
        return None


def base64_encode(data):
    """Simple base64 encoding for MicroPython."""
    return binascii.b2a_base64(data).strip().decode()


def compute_websocket_accept(key):
    """Compute Sec-WebSocket-Accept header value."""
    GUID = "258EAFA5-E914-47DA-95CA-5AB9A3F4ABDA"
    combined = key.strip() + GUID
    sha1_hash = hashlib.sha1(combined.encode()).digest()
    return base64_encode(sha1_hash)


def parse_http_headers(data):
    """Parse HTTP headers from the handshake request."""
    headers = {}
    lines = data.decode("utf-8").split("\r\n")
    request_line = lines[0] if lines else ""
    for line in lines[1:]:
        if ":" in line:
            key, value = line.split(":", 1)
            headers[key.strip().lower()] = value.strip()
    return request_line, headers


def websocket_handshake(client_socket):
    """Perform WebSocket handshake."""
    try:
        data = client_socket.recv(1024)
        if not data:
            return False

        request_line, headers = parse_http_headers(data)

        # Check if it's a regular HTTP request for the web page
        if "upgrade" not in headers or headers.get("upgrade", "").lower() != "websocket":
            serve_web_page(client_socket)
            return False

        ws_key = headers.get("sec-websocket-key", "")
        if not ws_key:
            return False

        accept_key = compute_websocket_accept(ws_key)

        response = (
            "HTTP/1.1 101 Switching Protocols\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            "Sec-WebSocket-Accept: {}\r\n"
            "\r\n"
        ).format(accept_key)

        client_socket.sendall(response.encode())
        return True
    except Exception as e:
        print("Handshake error:", e)
        return False


def decode_websocket_frame(data):
    """Decode a WebSocket frame and return the payload."""
    if len(data) < 2:
        return None, None

    first_byte = data[0]
    second_byte = data[1]

    opcode = first_byte & 0x0F
    masked = (second_byte & 0x80) != 0
    payload_length = second_byte & 0x7F

    offset = 2

    if payload_length == 126:
        if len(data) < 4:
            return None, None
        payload_length = struct.unpack(">H", data[2:4])[0]
        offset = 4
    elif payload_length == 127:
        if len(data) < 10:
            return None, None
        payload_length = struct.unpack(">Q", data[2:10])[0]
        offset = 10

    if masked:
        if len(data) < offset + 4:
            return None, None
        mask_key = data[offset:offset + 4]
        offset += 4

    if len(data) < offset + payload_length:
        return None, None

    payload = data[offset:offset + payload_length]

    if masked:
        payload = bytes([payload[i] ^ mask_key[i % 4] for i in range(len(payload))])

    return opcode, payload


def encode_websocket_frame(data, opcode=0x01):
    """Encode data into a WebSocket frame."""
    if isinstance(data, str):
        data = data.encode("utf-8")

    frame = bytearray()
    frame.append(0x80 | opcode)  # FIN + opcode

    length = len(data)
    if length < 126:
        frame.append(length)
    elif length < 65536:
        frame.append(126)
        frame.extend(struct.pack(">H", length))
    else:
        frame.append(127)
        frame.extend(struct.pack(">Q", length))

    frame.extend(data)
    return bytes(frame)


def send_ws_message(client_socket, message):
    """Send a JSON message over WebSocket."""
    if isinstance(message, dict):
        message = json.dumps(message)
    frame = encode_websocket_frame(message)
    try:
        client_socket.sendall(frame)
    except Exception as e:
        print("Send error:", e)


def handle_command(command):
    """Process incoming JSON commands and return response."""
    global device_state

    action = command.get("action", "")
    response = {"status": "ok", "action": action}

    if action == "turn_on":
        device_state["power"] = True
        led_pin.value(1)
        relay_pin.value(1)
        response["message"] = "Device turned ON"
        response["power"] = True

    elif action == "turn_off":
        device_state["power"] = False
        led_pin.value(0)
        relay_pin.value(0)
        response["message"] = "Device turned OFF"
        response["power"] = False

    elif action == "toggle":
        device_state["power"] = not device_state["power"]
        led_pin.value(1 if device_state["power"] else 0)
        relay_pin.value(1 if device_state["power"] else 0)
        response["message"] = "Device toggled"
        response["power"] = device_state["power"]

    elif action == "set_brightness":
        brightness = command.get("value", 0)
        brightness = max(0, min(100, int(brightness)))
        device_state["brightness"] = brightness
        # Use PWM for brightness control
        pwm = machine.PWM(led_pin, freq=1000, duty=int(brightness * 1023 / 100))
        response["message"] = "Brightness set to {}%".format(brightness)
        response["brightness"] = brightness

    elif action == "set_color":
        color = command.get("value", "white")
        device_state["color"] = color
        response["message"] = "Color set to {}".format(color)
        response["color"] = color

    elif action == "get_status":
        device_state["uptime"] = time.ticks_ms() // 1000
        # Read sensor data if available
        try:
            # Placeholder for actual sensor reading
            device_state["temperature"] = 25.0
            device_state["humidity"] = 60.0
        except Exception:
            pass
        response["state"] = device_state
        response["message"] = "Status retrieved"

    elif action == "restart":
        response["message"] = "Device restarting..."
        # Will restart after sending response
        return response, True

    elif action == "ping":
        response["message"] = "pong"
        response["timestamp"] = time.ticks_ms()

    else:
        response["status"] = "error"
        response["message"] = "Unknown action: {}".format(action)

    return response, False


